/*
Emitted when specified item has been selected. Only applicable in single selection mode.

[AllowReselect] must be enabled to reselect an item.

[AllowReselect]: https://pkg.go.dev/graphics.gd/classdb/ItemList#Instance.AllowReselect
*/
func (self Instance) OnItemSelected(cb func(index int), flags ...Signal.Flags) Instance {
	var flags_together Signal.Flags
	for _, flag := range flags {
		flags_together |= flag
	}
	gd.ObjectConnect(self.AsObject()[0], gd.NewStringName("item_selected"), gd.NewCallable(cb), int64(flags_together))
	return self
}

func (self class) ItemSelected() Signal.Any {
	return Signal.Via(gd.SignalProxy{}, pointers.Pack(gd.NewSignalOf(self.AsObject(), gd.NewStringName(`item_selected`))))
}

