func init() {
	gdclass.Register("ItemList", func(ptr gdreference.Object) any { return Instance{gdclass.NewItemList(ptr)} })
}

type IconMode int64 //gd:ItemList.IconMode

const (
	// Icon is drawn above the text.
	IconModeTop IconMode = 0
	// Icon is drawn to the left of the text.
	IconModeLeft IconMode = 1
)

type SelectMode int64 //gd:ItemList.SelectMode

const (
	// Only allow selecting a single item.
	SelectSingle SelectMode = 0
	// Allows selecting multiple items by holding Ctrl or Shift.
	SelectMulti SelectMode = 1
	// Allows selecting multiple items by toggling them on and off.
	SelectToggle SelectMode = 2
)

type ScrollHintMode int64 //gd:ItemList.ScrollHintMode

const (
	// Scroll hints will never be shown.
	ScrollHintModeDisabled ScrollHintMode = 0
	// Scroll hints will be shown at the top and bottom.
	ScrollHintModeBoth ScrollHintMode = 1
	// Only the top scroll hint will be shown.
	ScrollHintModeTop ScrollHintMode = 2
	// Only the bottom scroll hint will be shown.
	ScrollHintModeBottom ScrollHintMode = 3
)
